#include <bits/stdc++.h>
using namespace std;

void merge(vector<int>& nums1, int m, vector<int>& nums2, int n) {
    int last = m + n - 1;  // Last position in nums1
    int i = m - 1;         // Last valid element in nums1
    int j = n - 1;         // Last element in nums2

    // Start from the end and fill larger elements first
    while(j >= 0) {
        if(i >= 0 && nums1[i] > nums2[j]) {
            nums1[last] = nums1[i];
            i--;
        } else {
            nums1[last] = nums2[j];
            j--;
        }
        last--;
    }
}

int main() {
    int m, n;
    cin >> m >> n;

    vector<int> nums1(m + n);
    vector<int> nums2(n);

    // Input for array 1
    for(int i = 0; i < m + n; i++) {
        cin >> nums1[i];
    }

    // Input for array 2
    for(int i = 0; i < n; i++) {
        cin >> nums2[i];
    }

    merge(nums1, m, nums2, n);

    // Print merged array
    for(int i = 0; i < m + n; i++) {
        cout << nums1[i] << " ";
    }
    cout << endl;

    return 0;
}

